#define MAX_CONNS       10240
#define BUF_SIZE        4096
#define WRITE_BUF_SIZE  65536
#define IDLE_TIMEOUT_MS 30000
#define TIMER_HEAP_MAX  MAX_CONNS
#include <stdint.h>
#include <stddef.h>
#include <stdlib.h>
#include <string.h>
#include <sys/epoll.h>
#include <unistd.h>
